// ─────────────────────────────────────────────────────────────────────────
//  TEMPLATE RESOLVER
//  Derives the correct diagram template from existing site data.
//  No data modifications needed — reads goodFor, name, type, description.
//  Returns one of 9 distinct templates.
// ─────────────────────────────────────────────────────────────────────────
export type DiagramTemplate =
  | 'wreck'
  | 'wall'
  | 'cleaning-station'
  | 'bay-dropoff'
  | 'pinnacle'
  | 'drift'
  | 'muck'
  | 'jetty'
  | 'reef-slope'

export function getTemplate(site: DiveSite): DiagramTemplate {
  const n    = site.name.toLowerCase()
  const desc = site.description.toLowerCase()
  const gf   = site.goodFor.map(g => g.toLowerCase()).join(' ')
  const type = site.type
  const slug = site.slug

  // Explicit structure type — highest priority
  if (site.diagramType === 'wreck' || type === 'Wreck') return 'wreck'
  // Bay sites that also have walls — bay-dropoff takes priority over wall for diagram
  const bayPrioritySlugs = ['jemeluk-bay','jemeluk-bay-wall','jemeluk-bay-amed']
  if (bayPrioritySlugs.includes(slug)) return 'bay-dropoff'
  if (site.diagramType === 'wall'  || type === 'Wall')  return 'wall'
  if (type === 'Drift') return 'drift'

  // Jetty / pier — check BEFORE muck so police-pier/jetty muck dives show correctly
  if (n.includes('pier') || n.includes('jetty') || slug === 'kungkungan-bay' || slug === 'police-pier')
    return 'jetty'

  if (type === 'Muck')  return 'muck'

  // Cleaning station — manta aggregation sites (manta-bay is also a cleaning station)
  const mantaSlugs = ['manta-point','manta-bay','manta-ridge','manta-bay-amed']
  if (mantaSlugs.includes(slug) || (n.includes('manta') && !slug.includes('bay') && !slug.includes('jemeluk')))
    return 'cleaning-station'

  // Drift — goodFor or specific sites
  const driftSlugs = ['bunutan','gili-selang','kusambi','deep-blue-amed','deep-blue-amed-v1','sd-point','mangrove-point','alamanda-tulamben']
  if (gf.includes('drift diving') || driftSlugs.includes(slug))
    return 'drift'

  // Pinnacle / seamount — only true seamounts that rise from depth
  const pinnacleSlugs = ['cape-kri','sahaung','blue-magic','fukui-point','alung-banua','batu-kelebit','blue-magic']
  if (n.includes('seamount') || desc.includes('seamount') || desc.includes('rises from 400m') ||
      pinnacleSlugs.includes(slug))
    return 'pinnacle'

  // Bay / drop-off — explicit list of sheltered bay sites with distinct topography
  const baySlugs = ['crystal-bay','gamat-bay','emerald-bay-tulamben','jemeluk-bay',
                    'jemeluk-bay-wall','friwin-banda']
  if (baySlugs.includes(slug))
    return 'bay-dropoff'

  return 'reef-slope'
}

