export const TULAMBEN_EXTRA_SITES: DiveSite[] = [
  { slug:'tulamben-drop-off-wall',name:'The Drop-Off',area:'Tulamben',areaSlug:'tulamben',rank:2,type:'Wall',access:'Shore',minDepth:3,maxDepth:70,avgDepth:22,visibility:'15–30m',temp:'26–29°C',current:'None to mild',difficulty:'All levels',minCert:'Open Water',bestTime:'Morning',bestSeason:'Apr–Nov',goodFor:['Wall diving','Wide-angle photography','All levels','Macro'],facilities:['Shore access — 10 min walk from Liberty Wreck','Mimpi Resort nearby','All Tulamben dive shops service this site'],lat:-8.2765,lng:115.5960,rating:4.8,reviews:156,description:'A spectacular underwater cliff formed by the 1963 Mount Agung lava flow, plunging from 3m to 70m+. Draped in enormous gorgonian sea fans up to 2m wide at 30m, massive barrel sponges, and vibrant soft corals. A versatile multi-level site — beginners explore the shallow "aquarium" at 5m while advanced divers descend the dramatic deep wall. Frequent sightings of sharks, Napoleon wrasse, bumphead parrotfish, and occasional manta rays.',marineLife:[{name:'Napoleon wrasse',frequency:'common'},{name:'Bumphead parrotfish',frequency:'occasional'},{name:'Whitetip reef shark',frequency:'common'},{name:'Gorgonian sea fan',frequency:'very common'},{name:'Barrel sponge',frequency:'very common'}],safetyNotes:['Wall drops past 70m — stay within planned depth','Very clear water is deceptive — easy to drift deep','Back-reef at 5m perfect for long safety stops'],briefing:'Shore entry from pebble beach — 10 min walk east of Liberty Wreck. Swim to wall top at 3m. Beginners stay on shallow coral shelf (aquarium). Advanced divers descend wall to 30–40m. Large gorgonians at 30m. Ascend along wall for safety stop at 5m in back-reef.',emergencyContact:'BIMC Hospital Kuta: +62 361 761263',diagramType:'wall' },
  { slug:'tulamben-coral-garden',name:'Coral Garden Tulamben',area:'Tulamben',areaSlug:'tulamben',rank:3,type:'Reef',access:'Shore',minDepth:2,maxDepth:15,avgDepth:8,visibility:'15–30m',temp:'26–29°C',current:'None to mild',difficulty:'Beginner',minCert:'Open Water',bestTime:'Morning or night',bestSeason:'Year round',goodFor:['Beginners','Night diving','Artificial reef','Photography','Snorkelling'],facilities:['Dive shops along Tulamben beach','Resort restaurants','Equipment rinse tanks'],lat:-8.2755,lng:115.5945,rating:4.6,reviews:134,description:'A shallow sunlit reef blending natural coral formations with artistic artificial reef structures — a submerged Balinese temple gate, Buddha statues, stone sharks, turtles, dolphins, a TULAMBEN sign, and an old airplane frame, all encrusted with coral. Famous for blue ribbon eels in multiple life stages (black juvenile, blue male, yellow female). Perfect for long dives, night diving, and underwater photographers. Blue-spotted stingrays, peacock mantis shrimp, and abundant macro life.',marineLife:[{name:'Blue ribbon eel',frequency:'very common'},{name:'Blue-spotted stingray',frequency:'common'},{name:'Peacock mantis shrimp',frequency:'common'},{name:'Anemonefish',frequency:'very common'},{name:'Hawksbill turtle',frequency:'occasional'}],safetyNotes:['Shallow site — watch buoyancy near coral and statues','No touching artificial structures','Night dive: torch and buddy essential'],briefing:'Shore entry — walk south 5–10 min from Liberty Wreck. Descend to reef at 2–15m. Explore natural corals and artificial structures. Look for ribbon eels in burrows. Night: Spanish dancers, hunting octopus, sleeping fish. Shallow depth allows very long dives.',emergencyContact:'BIMC Hospital Kuta: +62 361 761263',diagramType:'shore' },
  { slug:'boga-wreck',name:'Boga Wreck (Kubu Wreck)',area:'Tulamben',areaSlug:'tulamben',rank:4,type:'Wreck',access:'Shore',minDepth:18,maxDepth:37,avgDepth:27,visibility:'15–25m',temp:'26–29°C',current:'None to mild',difficulty:'Advanced',minCert:'Advanced Open Water',bestTime:'Morning',bestSeason:'Year round',goodFor:['Wreck diving','Swim-throughs','Photography','Advanced training'],facilities:['Limited at Kubu beach','Relax Bali Dive Resort nearby','Tulamben dive shops 5 min drive'],lat:-8.2620,lng:115.5750,rating:4.7,reviews:108,description:'Bali\'s most exciting wreck after the Liberty — a decommissioned Indonesian coast guard patrol vessel deliberately sunk in 2012, sitting perfectly upright with 3 intact decks at 18–37m. Features spacious swim-throughs, the wheelhouse, a replica ship\'s wheel, and the famous Volkswagen Safari car in the cargo hold. Soft corals, schools of snappers, ribbon eels, and whitetip reef sharks have colonised the structure. Ideal for PADI Wreck Diver specialty training.',marineLife:[{name:'Ribbon eel',frequency:'common'},{name:'Whitetip reef shark',frequency:'occasional'},{name:'Schooling snapper',frequency:'very common'},{name:'Moray eel',frequency:'common'},{name:'Octopus',frequency:'occasional'}],safetyNotes:['Advanced Open Water minimum — depth 18–37m','Do not penetrate beyond safe swim-throughs','Shore approach from Kubu beach is a long swim'],briefing:'Shore entry at Kubu beach. Surface swim to wreck — descend to bow at 18m. Explore 3 decks from top down. Visit wheelhouse at mid-depth. Find VW Safari car in cargo hold at ~35m. Spacious swim-throughs throughout. Ascend for safety stop. Shore exit.',emergencyContact:'BIMC Hospital Kuta: +62 361 761263',diagramType:'wreck' },
  { slug:'batu-kelebit',name:'Batu Kelebit',area:'Tulamben',areaSlug:'tulamben',rank:5,type:'Drift',access:'Boat',minDepth:15,maxDepth:60,avgDepth:30,visibility:'15–30m',temp:'24–28°C',current:'Moderate to strong',difficulty:'Advanced',minCert:'Advanced Open Water',bestTime:'Mar–Oct',bestSeason:'Mar–Oct',goodFor:['Pelagics','Deep diving','Big fish','Currents'],facilities:['Jukung from Tulamben beach — no facilities at site'],lat:-8.2780,lng:115.5980,rating:4.7,reviews:84,description:'Tulamben\'s premier pelagic dive site — two massive underwater rock formations offshore with steep ridges, deep lava channels, and white sand between them. Nutrient-rich upwellings from the Lombok Strait attract schools of bigeye trevally, dogtooth tuna, barracuda, Napoleon wrasse, whitetip and blacktip reef sharks, and occasional eagle rays, thresher sharks, and whale sharks. Healthy hard and soft corals on the ridges. Excellent for technical diving certifications.',marineLife:[{name:'Dogtooth tuna',frequency:'common'},{name:'Schooling bigeye trevally',frequency:'very common'},{name:'Barracuda',frequency:'very common'},{name:'Reef shark',frequency:'common'},{name:'Eagle ray',frequency:'occasional'}],safetyNotes:['Strong currents bring upwellings — watch for downcurrents','Advanced divers only','Cold nutrient-rich water from Lombok Strait — thermoclines likely','Deep potential — strict NDL management'],briefing:'Jukung ride 5–10 min from Tulamben. Back-roll entry near rocks. Descend to ridges at 15–25m. Schools of trevally circle the rocks. Tuna and sharks in open water. Navigate white sand channels between ridges. Drift to exit point. SMB ascent — jukung follows bubbles.',emergencyContact:'BIMC Hospital Kuta: +62 361 761263',diagramType:'boat' },
  { slug:'alamanda-tulamben',name:'Alamanda',area:'Tulamben',areaSlug:'tulamben',rank:6,type:'Reef',access:'Boat',minDepth:5,maxDepth:30,avgDepth:18,visibility:'15–30m',temp:'26–29°C',current:'Calm to light',difficulty:'Intermediate',minCert:'Open Water',bestTime:'Morning',bestSeason:'Year round',goodFor:['Hidden gem','Healthy reef','Macro','Drift diving'],facilities:['Jukung from Tulamben — no shore facilities'],lat:-8.2770,lng:115.5970,rating:4.5,reviews:47,description:'Tulamben\'s most underrated site — east of the Drop-Off with varied topography of gentle slopes, coral bommies, rocky outcrops, short walls, and sand chutes. Less frequented than the main bay sites, offering a tranquil, uncrowded experience. Sea fans host pygmy seahorses (Bargibanti and Denise), leaf scorpionfish hide on rubble, and schooling fusiliers and anthias fill the water column. Flexible boat entry makes this ideal with light current.',marineLife:[{name:'Pygmy seahorse',frequency:'common'},{name:'Leaf scorpionfish',frequency:'occasional'},{name:'Schooling fusilier',frequency:'very common'},{name:'Octopus',frequency:'common'},{name:'Mantis shrimp',frequency:'common'}],safetyNotes:['Flexible entry — follow guide\'s lead on conditions','Can drift — stay together'],briefing:'Jukung from Tulamben (5–10 min east of Drop-Off). Flexible entry based on current. Descend to varied terrain at 5–25m. Work through coral bommies, rocky outcrops, and sand chutes. Check sea fans for pygmy seahorses. Flexible boat pickup.',emergencyContact:'BIMC Hospital Kuta: +62 361 761263',diagramType:'boat' },
  { slug:'batu-ringgit',name:'Batu Ringgit',area:'Tulamben',areaSlug:'tulamben',rank:7,type:'Muck',access:'Shore',minDepth:5,maxDepth:30,avgDepth:18,visibility:'10–25m',temp:'26–29°C',current:'None to mild',difficulty:'Intermediate',minCert:'Open Water',bestTime:'Morning',bestSeason:'Year round',goodFor:['Macro','Nudibranch','Photography','Hidden gem'],facilities:['Parking','Porter to beach','Toilet at site'],lat:-8.2570,lng:115.5720,rating:4.6,reviews:62,description:'Kubu\'s emerging macro photography hotspot — famous for the magnificent Iriomote Phyllodesmium nudibranch (~10cm), a large graceful creature found almost exclusively here among white hydroid patches at 28m. Volcanic sandy slopes with rubble patches and coral ridges host ghost pipefish, frogfish, whip coral shrimp, hawksbill turtles, ocellated frogfish, ornate pipefish, and emperor shrimp. Navigate to the white hydroid patches at 28m for the headline species.',marineLife:[{name:'Iriomote Phyllodesmium nudibranch',frequency:'occasional'},{name:'Ghost pipefish',frequency:'common'},{name:'Frogfish',frequency:'common'},{name:'Hawksbill turtle',frequency:'occasional'},{name:'Whip coral shrimp',frequency:'common'}],safetyNotes:['Navigation tricky — everything looks similar, use depth gauge','Worth diving to 28–30m for hydroid patches','Fewer crowds than main Tulamben sites'],briefing:'Shore entry over rounded pebbles at Kubu (north of Boga Wreck). Descend on volcanic slope. Navigate south using depth gauge. At 28m, locate two patches of white hydroids — Iriomote Phyllodesmium nudibranchs found here. Return via rubble patches checking for frogfish.',emergencyContact:'BIMC Hospital Kuta: +62 361 761263',diagramType:'shore' },
  { slug:'gerombong',name:'Gerombong',area:'Tulamben',areaSlug:'tulamben',rank:8,type:'Muck',access:'Shore',minDepth:4,maxDepth:30,avgDepth:14,visibility:'10–20m',temp:'26–29°C',current:'None to mild',difficulty:'Intermediate',minCert:'Open Water',bestTime:'Morning (avoid peak season crowds)',bestSeason:'Year round — avoid Feb, Jun–Sep crowds',goodFor:['Nudibranch','Macro','Cavern','Photography'],facilities:['Dedicated parking','Camera rinse tanks','Changing rooms','Toilets','Shaded beach setup'],lat:-8.2520,lng:115.5680,rating:4.7,reviews:143,description:'The northern crown jewel of Tulamben macro diving — offering the highest nudibranch diversity in the entire region. Black sand slope, coral walls, and a unique decorated underwater cavern (Pura Gerombong) at 13m near the temple. Golden spadefish (batfish family), giant cuttlefish, ghost pipefish, frogfish, and juvenile lionfish. Nitrox highly recommended for photographers to extend bottom time. Can get crowded in peak season.',marineLife:[{name:'Nudibranch',frequency:'very common'},{name:'Ghost pipefish',frequency:'common'},{name:'Frogfish',frequency:'common'},{name:'Giant cuttlefish',frequency:'occasional'},{name:'Golden spadefish',frequency:'occasional'}],safetyNotes:['Popular site — can be crowded with inexperienced divers kicking up silt','Cavern at 13m requires torch','Nitrox recommended for extended macro photography'],briefing:'Shore entry at Gerombong beach. Descend on black sand slope. Work systematically — every rubble piece is potential habitat. Left side: wall and reef with cuttlefish and batfish. Find cavern (Pura Gerombong) at 13m near temple — bring torch. Highest nudibranch density in the region.',emergencyContact:'BIMC Hospital Kuta: +62 361 761263',diagramType:'shore' },
  { slug:'sidem',name:'Sidem',area:'Tulamben',areaSlug:'tulamben',rank:9,type:'Muck',access:'Shore',minDepth:3,maxDepth:40,avgDepth:16,visibility:'10–25m',temp:'26–29°C',current:'None to mild',difficulty:'All levels',minCert:'Open Water',bestTime:'Morning',bestSeason:'Year round',goodFor:['Muck diving','Hidden gem','Macro','Reef diving'],facilities:['Rest area','Showers','Rinse tanks','Toilets','Local snack sellers'],lat:-8.2950,lng:115.6100,rating:4.6,reviews:78,description:'A hidden macro gem in a sheltered volcanic bay south of Tulamben. Two distinct dive profiles: muck diving on volcanic sand in the bay centre (nudibranchs, mantis shrimps, sea moths, boxer crabs, spiny seahorses, warty frogfish) or reef diving on the right side (turtles, leaf scorpionfish, whitetip reef sharks, hard corals). Fine black sand makes for smooth entry. Less visited than Seraya and Melasti — consistently uncrowded.',marineLife:[{name:'Spiny seahorse',frequency:'common'},{name:'Warty frogfish',frequency:'common'},{name:'Sea moth',frequency:'occasional'},{name:'Boxer crab',frequency:'occasional'},{name:'Whitetip reef shark',frequency:'occasional'}],safetyNotes:['Fine sand — excellent buoyancy essential','Two distinct zones — discuss plan with guide beforehand'],briefing:'Shore entry from fine black sand beach. Two options: centre (muck dive 5–25m) or turn right for reef (coral wall with turtles and sharks). Muck zone: systematic grid search of sand. Reef zone: follow coral right wall to corner, then return along centre.',emergencyContact:'BIMC Hospital Kuta: +62 361 761263',diagramType:'shore' },
  { slug:'emerald-bay-tulamben',name:'Emerald Bay',area:'Tulamben',areaSlug:'tulamben',rank:10,type:'Reef',access:'Boat',minDepth:12,maxDepth:30,avgDepth:20,visibility:'15–30m',temp:'26–29°C',current:'Calm to moderate',difficulty:'Intermediate',minCert:'Open Water',bestTime:'Morning',bestSeason:'Year round',goodFor:['Pristine coral','Unique scenery','Macro','Quiet site'],facilities:['Jukung from Tulamben — no shore facilities'],lat:-8.2800,lng:115.6000,rating:4.6,reviews:56,description:'A quieter, more pristine diving experience just beyond the busier Tulamben Bay. Light-coloured sand (stark contrast to Tulamben\'s black) and exceptionally healthy corals rarely visited by divers. Massive elephant ear sponges over 2m high, expansive layers of pink-orange and brown plating corals, feather stars, and a sunken table as artificial reef. Mola Mola possible at rising tide. Often has the site completely to yourself.',marineLife:[{name:'Elephant ear sponge',frequency:'very common'},{name:'Feather star',frequency:'very common'},{name:'Plating coral',frequency:'very common'},{name:'Mola mola',frequency:'rare'}],safetyNotes:['Can turn into drift dive if current picks up','Remote from main beach — boat essential'],briefing:'5-min jukung from Tulamben. Back-roll entry at sloping reef. Descend to light sand slope at 12–25m. Massive elephant ear sponges and plating corals. Can drift gently toward Tulamben if current picks up. Mola Mola at rising tide in season. SMB ascent — jukung follows.',emergencyContact:'BIMC Hospital Kuta: +62 361 761263',diagramType:'boat' },
  { slug:'palung-palung',name:'Palung Palung',area:'Tulamben',areaSlug:'tulamben',rank:11,type:'Reef',access:'Boat',minDepth:3,maxDepth:30,avgDepth:16,visibility:'15–25m',temp:'26–29°C',current:'None to mild',difficulty:'Intermediate',minCert:'Open Water',bestTime:'Morning',bestSeason:'Year round',goodFor:['Pristine reef','Hidden gem','Quiet diving','Coral diversity'],facilities:['5-min jukung from Tulamben'],lat:-8.2775,lng:115.5975,rating:4.6,reviews:39,description:'Tulamben\'s best-kept secret — an untouched site with a distinctive trough-like gully (palung means trough in Indonesian) that opens onto a coral-rich slope with fingers stretching into the blue. Astounding coral variety: brain, honeycomb, rose-coloured branching, mushroom, purple tube sponges, briar corals. Bumphead parrotfish, garden eels, turtles, reef sharks, batfish, tangs, moorish idols, clownfish. Very low diver traffic — often completely uncrowded.',marineLife:[{name:'Brain coral',frequency:'very common'},{name:'Bumphead parrotfish',frequency:'occasional'},{name:'Garden eel',frequency:'common'},{name:'Reef shark',frequency:'occasional'},{name:'Green turtle',frequency:'common'}],safetyNotes:['Less dived — navigate carefully with guide','Current can develop — check plan with guide'],briefing:'5-min jukung from Tulamben. Back-roll at gully. Descend into distinctive trough formation. Follow gully outward over the side to gradual slope. Explore finger ridges stretching into blue water. Enormous coral diversity. Return up gully to safety stop area.',emergencyContact:'BIMC Hospital Kuta: +62 361 761263',diagramType:'boat' },
  { slug:'segara-tulamben',name:'Segara',area:'Tulamben',areaSlug:'tulamben',rank:12,type:'Reef',access:'Shore',minDepth:4,maxDepth:30,avgDepth:12,visibility:'15–25m',temp:'26–29°C',current:'None',difficulty:'Beginner',minCert:'Open Water',bestTime:'Morning',bestSeason:'Year round',goodFor:['Beginners','Training','Macro','Artificial reef'],facilities:['Beach access near Segara Temple','Basic dive setup area'],lat:-8.2820,lng:115.6000,rating:4.4,reviews:67,description:'A calm versatile shore dive near Segara Temple — perfect for training and beginners. Shallow coral plateau at 3m transitions to sandy slope with rubble and artificial reef structures from 2008, now well-established with thriving coral growth. Left toward Emerald Bay: bigger coral structures, stingrays in sand, schooling mackerel. Macro: Costasiella "Shaun the Sheep" nudibranchs on specific halimeda algae patches, frogfish, and decorator crabs.',marineLife:[{name:'Costasiella nudibranch',frequency:'occasional'},{name:'Stingray',frequency:'common'},{name:'Frogfish',frequency:'occasional'},{name:'Decorator crab',frequency:'common'},{name:'Schooling mackerel',frequency:'occasional'}],safetyNotes:['Calm conditions — good for training','Shallow plateau — watch buoyancy near coral','Halimeda algae patches at 14–18m for Shaun the Sheep nudis'],briefing:'Shore entry near Segara Temple. Descend to coral plateau at 3m. Head left (east) for bigger coral structures and stingrays. At 14–18m, look for halimeda algae — Costasiella nudibranchs graze here. Artificial reef at 9m: check for frogfish and decorator crabs.',emergencyContact:'BIMC Hospital Kuta: +62 361 761263',diagramType:'shore' },
  { slug:'cantik-point',name:'Cantik Point',area:'Tulamben',areaSlug:'tulamben',rank:13,type:'Muck',access:'Shore',minDepth:4,maxDepth:30,avgDepth:14,visibility:'15–25m',temp:'26–29°C',current:'None to mild',difficulty:'All levels',minCert:'Open Water',bestTime:'Morning',bestSeason:'Year round',goodFor:['Quiet macro','Photography','Low traffic'],facilities:['Basic beach access only'],lat:-8.2810,lng:115.5990,rating:4.4,reviews:31,description:'"Cantik" means beautiful in Indonesian. A peaceful, little-visited macro dive between Segara and Melasti with very low diver traffic. Fine black sand and scattered coral patches provide ideal hiding spots for nudibranchs, pipefish, mantis shrimp, dragonets, frogfish, juvenile lionfish, and decorator crabs. Benefits from the same macro biodiversity as nearby Melasti but without the crowds. Best when local guides report it as "hot".',marineLife:[{name:'Nudibranch',frequency:'very common'},{name:'Pipefish',frequency:'common'},{name:'Dragonet',frequency:'occasional'},{name:'Frogfish',frequency:'occasional'},{name:'Mantis shrimp',frequency:'common'}],safetyNotes:['Remote quiet site — dive with guide','Move slowly on fine sand'],briefing:'Shore entry from small beach between Segara and Melasti. Descend on fine black sand slope. Systematic search of sparse rubble and coral patches. Check every sponge and sea grass tuft. Low traffic means undisturbed critters are more active and visible.',emergencyContact:'BIMC Hospital Kuta: +62 361 761263',diagramType:'shore' },
]

export function getTulambExtraSiteBySlug(slug:string){return TULAMBEN_EXTRA_SITES.find(s=>s.slug===slug)}
